from collections import defaultdict
from itertools import product, combinations
from copy import deepcopy

class Node:
    def __init__(self, value, color=None):
        self.value = value # Vertex number
        self.color = color # Color of the node
        self.out_neighbors = [] # Node pointing out from this Node
        self.in_neighbors = [] # Node pointing to this Node

    # Update both the nodes that are connected
    def add_out_neighbor(self, node):
        if self.color is not None and node.color is not None and self.color == node.color:
            print(f"Cannot connect Node {self.value} to Node {node.value}: same color ({self.color})")
        else:
            self.out_neighbors.append(node)
            node.in_neighbors.append(self)

    def __repr__(self):
        out_values = [f"{n.value}({n.color})" for n in self.out_neighbors]
        return f"Node {self.value} with color {self.color} -> {out_values}"
    
class Graph:
    def __init__(self, connections, vertexcolors):
        self.connections = connections
        self.vertexcolors = vertexcolors
        self.nodelist = []

        for value, color in self.vertexcolors.items():
            node = Node(value, color)
            self.nodelist.append(node)
        
        self.value_to_node = {node.value: node for node in self.nodelist}

        for in_vertex, out_vertex in self.connections:
            in_vertex = self.value_to_node[in_vertex]
            out_vertex = self.value_to_node[out_vertex]
            in_vertex.add_out_neighbor(out_vertex)

    def assign_color(self, node_value, color):
        self.value_to_node[node_value].color = color

    def get_vertex_colors(self):
        return {node.value: node.color for node in self.nodelist}
    
    def __repr__(self):
        return "\n".join(str(node) for node in self.nodelist)

def valid_graph(connections, vertexcolors):
    in_deg = {}

    for u, v in connections:
        if vertexcolors[u] == vertexcolors[v]:
            return False
        if v not in in_deg:
            in_deg[v] = 0
        in_deg[v] += 1

    for value, _ in vertexcolors:
        if in_deg.get(value, 0) != 2:
            return False
        
    return True

def generate_all_valid_graphs(vertexcolors):
    nodes = list(vertexcolors.keys())

    node_to_choices = {} # List all valid pairs of nodes it can connect to

    # I need to come back to this part
    for node in nodes: # for each node
        node_to_choices[node] = [] # initialize the key, value pair where key is the node and the value is an empty list
        for i in nodes: # iterate one node
            for j in nodes: # iterate another node at the same time
                if i != j and node != i and node != j and i < j:
                    node_to_choices[node].append([(node, i), (node, j)])

    all_combinations = product(*[node_to_choices[node] for node in nodes])

    valid_graphs = []
    for combo in all_combinations:
        edges = [edge for pair in combo for edge in pair]
        if valid_graph(edges, vertexcolors):
            print(edges)
            valid_graphs.append(edges)
    
    return valid_graphs

def build_valid_graphs(partial_edges, in_deg, out_deg, nodes, result, vertexcolors):
    if len(partial_edges) == len(nodes) * 2:
        if all(in_deg.get(n, 0) == 2 for n in nodes):
            result.append(list(partial_edges))
        return

    current_node = nodes[len(partial_edges) // 2]
    for i in nodes:
        for j in nodes:
            if i == j or current_node == i or current_node == j:
                continue
            if vertexcolors[current_node] == vertexcolors[i] or vertexcolors[current_node] == vertexcolors[j]:
                continue
            if in_deg.get(i, 0) >= 2 or in_deg.get(j, 0) >= 2:
                continue
            edges = [(current_node, i), (current_node, j)]

            partial_edges.extend(edges)
            in_deg[i] = in_deg.get(i, 0) + 1
            in_deg[j] = in_deg.get(j, 0) + 1

            build_valid_graphs(partial_edges, in_deg, out_deg, nodes, result, vertexcolors)

            partial_edges.pop()
            partial_edges.pop()
            in_deg[i] -= 1
            in_deg[j] -= 1

# Helper function 1 confirm a node is valid in that it doesn't have any adjacent nodes with same color
def is_valid(node, color):
    return all(neighbor.color != color for neighbor in node.out_neighbors + node.in_neighbors)

# Helper function 2 Recursive heart of the algorithm 
def backtrack(index, layer_idx, layers, colors, graph):
    # Base case
    if index == len(layers[layer_idx]):
        if layer_idx + 1 < len(layers):
            return backtrack(0, layer_idx + 1, layers, colors, graph)
        return True
    
    node_id = layers[layer_idx][index]
    node = graph.value_to_node[node_id]

    color_options = colors if layer_idx > 0 or index > 2 else [colors[index % 3]]

    for color in color_options:
        if is_valid(node, color):
            node.color = color
            if backtrack(index + 1, layer_idx, layers, colors, graph):
                return True
            node.color = None

    return False

def generate_valid_coloring(connections, layers):
    vertexcolors = {node: None for layer in layers for node in layer} # Initialize
    colors = ["Red", "Green", "Blue"]
    graph = Graph(connections, vertexcolors)
    
    # Hard code the start to reduce seach space
    for i, node in enumerate(layers[0][:3]):
        graph.value_to_node[node].color = colors[i % 3]

    if not backtrack(3, 0, layers, colors, graph):
        print("No valid coloring found")
        return None

    return {node.value: node.color for node in graph.nodelist}

# Converts the edges from wolfram to connections variable format
def extract_connections_from_wolfram(code):
    return_char = ["[", "("]
    tokens = code.split(" ")

    for i in range(len(tokens)):
        if tokens[i] == "->":
            tokens[i] = ", "
        if tokens[i][0] == "{":
            tokens[i] = tokens[i][1:]
        if tokens[i][0] == '"':
            tokens[i] = tokens[i][1:]
        if tokens[i][-1] == "}":
            tokens[i] = tokens[i][:-1]
        if tokens[i][-1] == ',':
            tokens[i] = tokens[i][:-1]
        if tokens[i][-1] == '"':
            tokens[i] = tokens[i][:-1]
        
    
    for i in range(len(tokens)):
        if i == len(tokens) - 1:
            tokens[i] = tokens[i] + ")"
        elif i % 3 == 0:
            tokens[i] = "(" + tokens[i]
        elif i % 3 == 2:
            tokens[i] = tokens[i] + "), "
    
    return "[" + ("".join(tokens)) + "]"

# Convert the vertexlabels to wolfram format to be passed within the Graph function
def convert_vertex_labels_to_wolfram(vertexlabels):
    parts = []
    for node, color in vertexlabels.items():
        parts.append(f'"{node}" -> {color}')
    return "{" + ", ".join(parts) + "}"

# Swaps two vertices given two variables
# Code assumes that its string is a list of edges with -> in between each ingoing and outgoing node, followed by a , if it's followed by more edges afterward
# Ex: {"1" -> "2", "1" -> "5", "2" -> "4", "2" -> "3", "3" -> "6", "3" -> "1", "4" -> "6", "4" -> "1", "5" -> "3", "5" -> "4", "6" -> "2", "6" -> "5"}
def swap_two_vertices(code, ver1, ver2):
    # Temporary replacement to avoid collisions
    code = code.replace(f'"{ver1}"', '"x"')
    code = code.replace(f'"{ver2}"', '"y"')
    code = code.replace('"x"', f'"{ver2}"')
    code = code.replace('"y"', f'"{ver1}"')
    return code

